import React from "react";
import ReactSlider from "react-slider";

const Filters = ({
                     yearRange,
                     setYearRange,
                     widthRange,
                     setWidthRange,
                     heightRange,
                     setHeightRange,
                     unit,
                     setUnit,
                     mediumMaterialFilters,
                     setMediumMaterialFilters,
                     filterData,
                 }) => {
    const mediumMaterialOptions = [
        "aluminum can",
        "animation",
        "bolts",
        "canvas",
        "carpet",
        "colored pencil",
        "digital video",
        "dumpster",
        "found metal",
        "hardware",
        "ink",
        "LEGO piece",
        "magic the gathering card",
        "magnets",
        "metal hardware",
        "monitor",
        "neon",
        "nerf dart",
        "nerf gun",
        "oil",
        "paint",
        "paper",
        "aluminum",
        "metal",
        "steel",
        "Repurposed scaffold",
        "sharpie",
        "spray paint",
        "steel bolts",
        "stickers",
        "super soaker",
        "UV print",
        "vinyl",
        "water",
        "weaving loop",
        "wood",
    ];

    const handleSliderChange = (values, setRange, sliderId) => {
        setRange(values);
        filterData();

        // Dynamically update the track gradient
        const sliderElement = document.getElementById(sliderId);
        if (sliderElement) {
            const [min, max] = values;
            const sliderMin = parseInt(sliderElement.getAttribute("aria-valuemin"), 10);
            const sliderMax = parseInt(sliderElement.getAttribute("aria-valuemax"), 10);

            const start = ((min - sliderMin) / (sliderMax - sliderMin)) * 100;
            const end = ((max - sliderMin) / (sliderMax - sliderMin)) * 100;

            sliderElement.style.setProperty("--start", `${start}%`);
            sliderElement.style.setProperty("--end", `${end}%`);
        }
    };

    const handleUnitChange = (e) => {
        setUnit(e.target.value);
        filterData();
    };

    const handleCheckboxChange = (e) => {
        const { value, checked } = e.target;
        setMediumMaterialFilters(prev =>
            checked ? [...prev, value] : prev.filter(item => item !== value)
        );
        filterData();
    };

    return (
        <aside className="filters">
            <h2>Filters</h2>

            {/* Year Range Slider */}
            <div className="filter-section">
                <label>Year Range:</label>
                <ReactSlider
                    id="year-slider"
                    className="slider"
                    thumbClassName="thumb"
                    trackClassName="track"
                    value={yearRange}
                    onChange={(values) => handleSliderChange(values, setYearRange, "year-slider")}
                    min={2011}
                    max={2025}
                    pearling
                    minDistance={1}
                />
                <span>{yearRange[0]} - {yearRange[1]}</span>
            </div>

            {/* Unit Selector */}
            <div className="filter-section">
                <label htmlFor="unit-select">Dimensions Unit:</label>
                <select id="unit-select" value={unit} onChange={handleUnitChange}>
                    <option value="Dimensions (inches)">Inches</option>
                    <option value="Dimensions (cm)">Centimeters</option>
                </select>
            </div>

            {/* Width Slider */}
            <div className="filter-section">
                <label>Width ({unit}):</label>
                <ReactSlider
                    id="width-slider"
                    className="slider"
                    thumbClassName="thumb"
                    trackClassName="track"
                    value={widthRange}
                    onChange={(values) => handleSliderChange(values, setWidthRange, "width-slider")}
                    min={0}
                    max={100}
                    pearling
                    minDistance={1}
                />
                <span>{widthRange[0]} - {widthRange[1]} {unit}</span>
            </div>

            {/* Height Slider */}
            <div className="filter-section">
                <label>Height ({unit}):</label>
                <ReactSlider
                    id="height-slider"
                    className="slider"
                    thumbClassName="thumb"
                    trackClassName="track"
                    value={heightRange}
                    onChange={(values) => handleSliderChange(values, setHeightRange, "height-slider")}
                    min={0}
                    max={100}
                    pearling
                    minDistance={1}
                />
                <span>{heightRange[0]} - {heightRange[1]} {unit}</span>
            </div>

            {/* Medium-Material Checkboxes */}
            <div className="filter-section">
                <label>Medium-Material:</label>
                <div className="checkbox-group">
                    {mediumMaterialOptions.map((option, index) => (
                        <label key={index}>
                            <input
                                type="checkbox"
                                value={option}
                                onChange={handleCheckboxChange}
                            />
                            {option}
                        </label>
                    ))}
                </div>
            </div>
        </aside>
    );
};

export default Filters;
